using System;

namespace SqlBuild.BackupExample
{
    class Program
    {
        static void Main(string[] args)
        {
            var connectionString = args.Length > 0 ? args[0] : "Server=localhost;Integrated Security=true;";
            var databaseName = args.Length > 1 ? args[1] : "model";
            var backupPath = args.Length > 2 ? args[2] : "obj/model_backup.bak";
            var compress = args.Length > 3 && bool.TryParse(args[3], out var result) && result;

            Console.WriteLine($"Backing up database '{databaseName}' to '{backupPath}' (compress={compress}) connection='{connectionString}'");

            BackupDatabase(connectionString, databaseName, backupPath, compress);
        }

        static void BackupDatabase(string connectionString, string database, string backupPath, bool compress = false)
        {
            using (var conn = new System.Data.SqlClient.SqlConnection(connectionString))
            {
                conn.InfoMessage += (sender, e) => Console.WriteLine(e.Message);
                conn.FireInfoMessageEventOnUserErrors = true;
                conn.Open();

                using (var command = conn.CreateCommand())
                {
                    command.CommandText = @"if ((select value_in_use from sys.configurations where name = 'clr enabled') = 0)
begin
    Exec sp_configure 'show advanced options', 1; RECONFIGURE; exec sp_configure 'clr enabled', 1; RECONFIGURE; EXEC sp_configure 'show advanced options', 0; RECONFIGURE;
end

declare @hash varbinary(64) = CONVERT(varbinary(64), 'B57CCBC3F448F07D1B664052364DA1094BD11D631C045FCAE83C3DAD9565AB4D9C4303FEFC67507603B8A4A987BF68D46DC4DDBBA2C4FCF7A3548F41BDBCCB4E', 2);
BEGIN TRY
    exec sp_add_trusted_assembly @hash, N'sqlbuildbackup, version=0.0.0.0, culture=neutral, publickeytoken=null, processorarchitecture=msil''sqlbuildbackup, version=0.0.0.0, culture=neutral, publickeytoken=null, processorarchitecture=msil';
    create assembly sqlbuildbackup authorization [dbo] from 
    with permission_set = unsafe;
    execute sp_executesql N'create procedure CreateBackup(@name nvarchar(max), @backup varbinary(max) output, @compressed bit = 0) as external name sqlbuildbackup.[SQLBuild.Functions].CreateBackup'
    exec CreateBackup @name, @backup output, @compress
END TRY
BEGIN CATCH print ERROR_MESSAGE() END CATCH

BEGIN TRY exec sp_drop_trusted_assembly @hash END TRY BEGIN CATCH END CATCH
BEGIN TRY drop procedure dbo.CreateBackup END TRY BEGIN CATCH END CATCH
BEGIN TRY drop assembly sqlbuildbackup END TRY BEGIN CATCH END CATCH
";

                    var nameParam = new System.Data.SqlClient.SqlParameter("@name", database);
                    var backupParam = new System.Data.SqlClient.SqlParameter("@backup", System.Data.SqlDbType.VarBinary, -1)
                    {
                    Direction = System.Data.ParameterDirection.Output
                    };
                    var compressParam = new System.Data.SqlClient.SqlParameter("@compress", compress);

                    command.Parameters.Add(nameParam);
                    command.Parameters.Add(backupParam);
                    command.Parameters.Add(compressParam);

                    command.ExecuteNonQuery();

                    var backupBytes = backupParam.Value as byte[];
                    if (backupBytes != null)
                    {
                        System.IO.File.WriteAllBytes(backupPath, backupBytes);
                    }
                }
                conn.Close();
            }
        }
    }
}
